// ---------- Engagement ----------

var commentTemplates = []string{
	"Огонь!", "Цвета невероятные", "Вау, вид супер", "А где это снято?",
	"Кайф", "Поздравляю!", "Топчик", "Отличная работа!", "Шикарно",
	"Свет идеальный", "Очень вдохновляет", "Цели!", "Так держать!",
	"Невероятно", "Талантище", "Стиль безупречен",
}

func seedComments(ctx context.Context, tx pgx.Tx) error {
	cnt := 0
	for _, p := range posts {
		// Each post gets 2-3 comments from users that aren't the owner. Deterministic.
		for k := 1; k <= 3; k++ {
			commenterIdx := ((p.idx*7 + k*11) % len(mainUsers)) + 1
			if commenterIdx == p.ownerIdx {
				commenterIdx = (commenterIdx % len(mainUsers)) + 1
			}
			tmpl := commentTemplates[(p.idx+k)%len(commentTemplates)]
			cnt++
			_, err := tx.Exec(ctx, `
				INSERT INTO comments (id, post_id, user_id, text)
				VALUES ($1,$2,$3,$4)
				ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text`,
				uid(pComment, cnt), uid(pPost, p.idx), uid(pUser, commenterIdx), tmpl)
			if err != nil {
				return err
			}
		}
	}
	return nil
}

func seedLikesOnPosts(ctx context.Context, tx pgx.Tx) error {
	// Engagement is generated by JOIN — no hardcoded post UUIDs anywhere.
	// Rule: every user (main + brand) likes ~70% of posts, except their own.
	_, err := tx.Exec(ctx, `
		INSERT INTO likes (user_id, entity_id, entity_type)
		SELECT u.id, p.id, 'post'
		FROM users u
		CROSS JOIN posts p
		WHERE u.id != p.user_id
		  AND (hashtext(u.id::text || p.id::text) % 10) < 7
		ON CONFLICT (user_id, entity_id, entity_type) DO NOTHING`)
	return err
}

func seedSavedPosts(ctx context.Context, tx pgx.Tx) error {
	_, err := tx.Exec(ctx, `
		INSERT INTO saved_posts (user_id, post_id)
		SELECT u.id, p.id
		FROM users u
		CROSS JOIN posts p
		WHERE u.id != p.user_id
		  AND (hashtext(u.id::text || p.id::text) % 10) < 2
		ON CONFLICT DO NOTHING`)
	return err
}

func seedFollows(ctx context.Context, tx pgx.Tx) error {
	// Every main user follows every other main user.
	if _, err := tx.Exec(ctx, `
		INSERT INTO follows (follower_id, following_id)
		SELECT a.id, b.id
		FROM users a
		CROSS JOIN users b
		WHERE a.id != b.id
		  AND a.id::text LIKE 'a0000000%'
		  AND b.id::text LIKE 'a0000000%'
		ON CONFLICT DO NOTHING`); err != nil {
		return err
	}
	// Every main user follows every brand.
	_, err := tx.Exec(ctx, `
		INSERT INTO follows (follower_id, following_id)
		SELECT a.id, b.id
		FROM users a
		CROSS JOIN users b
		WHERE a.id::text LIKE 'a0000000%'
		  AND b.id::text LIKE 'b0000000%'
		ON CONFLICT DO NOTHING`)
	return err
}

func seedNotifications(ctx context.Context, tx pgx.Tx) error {
	// Wipe & rebuild: notifications are derived state, easier to regenerate from current relations.
	if _, err := tx.Exec(ctx, `
		DELETE FROM notifications WHERE id::text LIKE '90000000%'`); err != nil {
		return err
	}
	// One notif per like, one per comment, one per follow — capped to keep the table sane.
	queries := []string{
		`INSERT INTO notifications (id, user_id, from_user_id, type, entity_id, entity_type, message)
		 SELECT ('` + pNotif + `' || lpad((row_number() OVER ())::text, 12, '0'))::uuid,
		        p.user_id, l.user_id, 'like', p.id, 'post', 'liked your post'
		 FROM likes l JOIN posts p ON p.id = l.entity_id
		 WHERE l.entity_type = 'post' AND p.user_id != l.user_id
		 LIMIT 30
		 ON CONFLICT (id) DO NOTHING`,
		`INSERT INTO notifications (id, user_id, from_user_id, type, entity_id, entity_type, message)
		 SELECT ('` + pNotif + `1' || lpad((row_number() OVER ())::text, 11, '0'))::uuid,
		        p.user_id, c.user_id, 'comment', p.id, 'post', 'commented on your post'
		 FROM comments c JOIN posts p ON p.id = c.post_id
		 WHERE p.user_id != c.user_id
		 LIMIT 30
		 ON CONFLICT (id) DO NOTHING`,
		`INSERT INTO notifications (id, user_id, from_user_id, type, message)
		 SELECT ('` + pNotif + `2' || lpad((row_number() OVER ())::text, 11, '0'))::uuid,
		        f.following_id, f.follower_id, 'follow', 'started following you'
		 FROM follows f
		 LIMIT 30
		 ON CONFLICT (id) DO NOTHING`,
	}
	for _, q := range queries {
		if _, err := tx.Exec(ctx, q); err != nil {
			return err
		}
	}
	return nil
}

